<?php
declare(strict_types=1);session_start();[$pdo,$c]=require __DIR__.'/db.php';
if(isset($_POST['logout'])){session_destroy();header('Location: admin.php');exit;}
if(!($_SESSION['admin']??false)){if(isset($_POST['user'],$_POST['pass'])&&hash_equals((string)$c['admin_user'],(string)$_POST['user'])&&password_verify((string)$_POST['pass'],(string)$c['admin_password_hash'])){$_SESSION['admin']=true;header('Location: admin.php');exit;}$login=true;}else{$login=false;$stats=$pdo->query("SELECT (SELECT COUNT(*) FROM visitors) visitors,(SELECT COALESCE(SUM(return_count),0) FROM visitors) returns,(SELECT COUNT(*) FROM visitor_events WHERE event_type='search') searches,(SELECT COUNT(*) FROM visitor_events) events")->fetch();$visitors=$pdo->query("SELECT visitor_code,created_at,updated_at,return_count,calculator_data FROM visitors ORDER BY updated_at DESC LIMIT 200")->fetchAll();$events=$pdo->query("SELECT visitor_code,event_type,created_at,event_data FROM visitor_events ORDER BY id DESC LIMIT 300")->fetchAll();}
?><!doctype html><html lang="ar" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>لوحة مالك الحاسبة</title><style>body{font-family:Tahoma;background:#f4f8f7;color:#102a43;margin:0;padding:20px}.box{max-width:1100px;margin:auto;background:#fff;border-radius:18px;padding:20px;box-shadow:0 8px 30px #0001}input,button{padding:12px;border:1px solid #ccd;border-radius:10px;font:inherit}button{background:#0b6b62;color:#fff}table{width:100%;border-collapse:collapse;margin-top:16px}th,td{padding:9px;border-bottom:1px solid #ddd;text-align:right;vertical-align:top}.cards{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.card{background:#eef8f6;padding:15px;border-radius:12px}.num{font-size:28px;font-weight:bold}@media(max-width:700px){.cards{grid-template-columns:1fr 1fr}.scroll{overflow:auto}}</style></head><body><main class="box">
<?php if($login):?><h1>دخول مالك النظام</h1><form method="post"><input name="user" required placeholder="اسم المستخدم"><input name="pass" type="password" required placeholder="كلمة المرور"><button>دخول</button></form>
<?php else:?><form method="post" style="float:left"><button name="logout">خروج</button></form><h1>لوحة التحليلات</h1><div class="cards"><div class="card">الزوار<div class="num"><?=$stats['visitors']?></div></div><div class="card">مرات العودة<div class="num"><?=$stats['returns']?></div></div><div class="card">عمليات البحث<div class="num"><?=$stats['searches']?></div></div><div class="card">جميع الأحداث<div class="num"><?=$stats['events']?></div></div></div><h2>الزوار والبيانات</h2><div class="scroll"><table><tr><th>الرقم</th><th>الإنشاء</th><th>آخر تحديث</th><th>مرات العودة</th><th>البيانات</th></tr><?php foreach($visitors as $v):?><tr><td><?=htmlspecialchars($v['visitor_code'])?></td><td><?=$v['created_at']?></td><td><?=$v['updated_at']?></td><td><?=$v['return_count']?></td><td><details><summary>عرض</summary><pre><?=htmlspecialchars(json_encode(json_decode($v['calculator_data'],true),JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT))?></pre></details></td></tr><?php endforeach?></table></div><h2>آخر العمليات</h2><div class="scroll"><table><tr><th>الزائر</th><th>العملية</th><th>الوقت</th><th>التفاصيل</th></tr><?php foreach($events as $e):?><tr><td><?=htmlspecialchars($e['visitor_code']??'-')?></td><td><?=htmlspecialchars($e['event_type'])?></td><td><?=$e['created_at']?></td><td><?=htmlspecialchars($e['event_data']??'')?></td></tr><?php endforeach?></table></div><?php endif?></main></body></html>

